import { masterEndpoint } from './endpoint';
import { downloadCatalogCsv } from '../../utils/exportCatalogCsv';
import type {
  CustomerDto,
  DepartmentDto,
  UnitDto,
  WarehouseDto,
  MaterialGroupDto,
  CustomerGroupDto,
} from './models';

const EXPORT_PAGE_SIZE = 500;

export async function exportCustomersCsv(params?: { search?: string; customerType?: string }) {
  const { items } = await masterEndpoint.getCustomers({
    ...params,
    page: 1,
    pageSize: EXPORT_PAGE_SIZE,
  });
  downloadCatalogCsv(
    `DoiTuong-${new Date().toISOString().slice(0, 10)}`,
    ['Mã', 'Tên', 'Loại', 'Mã số thuế', 'TK', 'Trạng thái'],
    items.map(c => [
      c.code,
      c.name,
      c.customerType ?? '',
      c.taxCode ?? '',
      c.accountCode ?? '',
      c.isActive,
    ]),
  );
}

